Here's an example code for a Discord bot using Discord.js v14 that implements a single slash command, `ban`:
```javascript
const { Client, GatewayIntentBits } = require('discord.js');
const client = new Client({
  intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMembers],
});

client.commands = new Map();

// Define the ban command
client.commands.set('ban', {
  name: 'ban',
  description: 'Bans a member from the server',
  options: [
    {
      name: 'member',
      description: 'The member to ban',
      type: 'user',
      required: true,
    },
    {
      name: 'reason',
      description: 'Optional reason for the ban',
      type: 'string',
    },
  ],
  async execute(interaction) {
    const member = interaction.options.getMember('member');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    // Implement your ban logic here
    // For example, using Discord.js's built-in methods:
    await member.ban({ reason });

    // Respond to the interaction
    await interaction.reply(`Banned ${member.user.username} for ${reason}`);
  },
});

client.once('ready', () => {
  console.log('Bot is ready!');
});

client.login('YOUR_DISCORD_BOT_TOKEN');
```
