function findPrimeNumbers(arr) {
  for (const num of arr) {
    if (isPrime(num)) {
      console.log(`Found prime number: ${num}`);
      return; // exit early, only print the first prime number found
    }
  }
}

function isPrime(n) {
  if (n <= 1) return false; // 0 and 1 are not prime
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) return false; // if divisible, not prime
  }
  return true; // n is prime
}

// Example usage:
const numbers = [4, 7, 11, 20, 23];
findPrimeNumbers(numbers);
```
Here's an explanation:

1. The `findPrimeNumbers` function iterates through the input array using a `for...of` loop.
2. For each number, it calls the `isPrime` helper function to check if it's prime.
3. If `isPrime` returns `true`, the function logs the prime number to the console and exits early using `return`. This ensures we only print the first prime number found.
4. The `isPrime` function uses a simple trial division method to check if a number is prime:
	* It checks if the number is less than or equal to 1 (not prime).
	* Then, it iterates from 2 to the square root of the number (inclusive), checking if the number is divisible by any of these values. If it is, it's not prime.
	* If none of these conditions apply, the number is prime, and the function returns `true`.

